const slot = Math.floor(Date.now() / 14400000);
const out  = { slot, ts: new Date().toISOString() };

// 1. DuckDuckGo
try {
  const d = await $fetch('https://api.duckduckgo.com/?q=evez666+autonomous+AI+defi&format=json&no_html=1&skip_disambig=1',
    {headers:{'User-Agent':'EVEZ-OS/2.0'}});
  out.ddg = {abstract:(d.AbstractText||'').slice(0,300), related:(d.RelatedTopics||[]).slice(0,4).map(t=>(t.Text||'').slice(0,80)).filter(Boolean)};
} catch(e){out.ddg={};}

// 2. Reddit (no key)
out.reddit=[];
for(const q of ['evez666','defi autonomous agent 2026','AI meme crypto autonomous']){
  try{
    const r=await $fetch('https://www.reddit.com/search.json?q='+encodeURIComponent(q)+'&sort=hot&limit=3&t=week',
      {headers:{'User-Agent':'EVEZ-OS/2.0'}});
    (r.data&&r.data.children?r.data.children:[]).forEach(p=>
      out.reddit.push({t:(p.data.title||'').slice(0,100),s:p.data.score,r:p.data.subreddit}));
  }catch(e2){}
}
out.reddit=out.reddit.slice(0,8);

// 3. HackerNews Algolia (no key)
try{
  const hn=await $fetch('https://hn.algolia.com/api/v1/search?query=autonomous+AI+agent+DeFi&hitsPerPage=5');
  out.hn=(hn.hits||[]).map(h=>({t:(h.title||'').slice(0,100),p:h.points}));
}catch(e){out.hn=[];}

// 4. CoinGecko trending
try{
  const cg=await $fetch('https://api.coingecko.com/api/v3/search/trending');
  out.trending=(cg.coins||[]).slice(0,5).map(c=>({n:c.item.name,sym:c.item.symbol,
