}catch(e){out.trending=[];}

// 5. CoinGecko global market
try{
  const gm=await $fetch('https://api.coingecko.com/api/v3/global');
  const gd=gm.data||{};
  out.market={
    mcap:gd.total_market_cap&&gd.total_market_cap.usd?(gd.total_market_cap.usd/1e12).toFixed(2)+'T':'?',
    btc_dom:gd.market_cap_percentage?gd.market_cap_percentage.btc.toFixed(1)+'%':'?',
    chg_24h:gd.market_cap_change_percentage_24h_usd?gd.market_cap_change_percentage_24h_usd.toFixed(2)+'%':'?'
  };
}catch(e){out.market={};}

// 6. Fear & Greed
try{
  const fg=await $fetch('https://api.alternative.me/fng/?limit=3');
  out.fear_greed=(fg.data||[]).slice(0,3).map(d=>({val:d.value,label:d.value_classification}));
}catch(e){out.fear_greed=[];}

// 7. Nitter — scrape @evez666 public tweets
out.evez666_tweets=[];
for(const mirror of ['https://nitter.privacydev.net','https://nitter.poast.org','https://nitter.cz']){
  try{
    const html=await $fetch(mirror+'/evez666',{headers:{'User-Agent':'Mozilla/5.0 EVEZ-OS'}});
    const re=/class="tweet-content[^"]*"[^>]*>([\s\S]{10,280}?)<\/div>/g;
    let m,found=[];
    while((m=re.exec(html))!==null&&found.length<5){
      const clean=m[1].replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
      if(clean.length>15)found.push(clean.slice(0,200));
    }
    if(found.length){out.evez666_tweets=found;break;}
  }catch(e2){}
}

// 8. GitHub trending AI repos
try{
  const gh=await $fetch('https://api.github.com/search/repositories?q=autonomous+AI+agent&sort=stars&order=desc&per_page=3',
    {headers:{'User-Agent':'EVEZ-OS/2.0'}});
  out.github=(gh.items||[]).map(r=>({name:r.full_name,stars:r.stargazers_count,desc:(r.description||'').slice(0,80)}));
}catch(e){out.github=[];}

// 9. Mempool BTC fees
try{
  const mp=await $fetch('https://mempool.space/api/v1/fees/recommended');
  out.btc_fees={fastest:mp.fastestFee,hour:mp.hourFee,economy:mp.economyFee};
}catch(e){out.btc_fees={};}

// 10. Gitcoin grants (public GraphQL)
try{
  const gc=await $fetch('https://grants-stack-indexer-v2.gitcoin.co/graphql',{
    method:'POST',headers:{'Content-Type':'application/json'},
    body:JSON.stringify({query:'{ rounds(first:3,orderBy:createdAtBlock,orderDirection:desc){id roundMetadata{name}matchAmountInUsd} }'})
  });
  out.grants=(gc.data&&gc.data.rounds?gc.data.rounds:[]).map(r=>({name:(r.roundMetadata&&r.roundMetadata.name)||'?',match_usd:r.matchAmountInUsd}));
}catch(e){out.grants=[];}

return [{json:out}];

const cfg = $('Config').first().json;
const s   = $('OmniScout').first().json;

async function think(sys, usr) {
  const max = 1400;
  if (cfg.groq && cfg.groq !== 'PASTE_GROQ_KEY_HERE') {
    try {
      const r = await $fetch('https://api.groq.com/openai/v1/chat/completions',{
        method:'POST',
        headers:{'Authorization':'Bearer '+cfg.groq,'Content-Type':'application/json'},
        body:JSON.stringify({model:'llama-3.3-70b-versatile',max_tokens:max,
          messages:[{role:'system',content:sys},{role:'user',content:usr}]})
      });
      const t=r.choices[0].message.content;
      try{return{out:JSON.parse(t.replace(/```json|```/g,'').trim()),via:'groq'};}
      catch{return{out:{raw:t.slice(0,800)},via:'groq'};}
    }catch(e){}
  }
  if (cfg.gemini && cfg.gemini !== 'PASTE_GEMINI_KEY_HERE') {
    try {
      const r = await $fetch('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key='+cfg.gemini,{
        method:'POST',headers:{'Content-Type':'application/json'},
        body:JSON.stringify({systemInstruction:{parts:[{text:sys}]},
          contents:[{role:'user',parts:[{text:usr}]}],
          generationConfig:{maxOutputTokens:max}})
      });
      const t=r.candidates[0].content.parts[0].text;
      try{return{out:JSON.parse(t.replace(/```json|```/g,'').trim()),via:'gemini'};}
      catch{return{out:{raw:t.slice(0,800)},via:'gemini'};}
    }catch(e){}
  }
  if (cfg.or_key && cfg.or_key !== 'PASTE_OR_KEY_HERE') {
    try {
      const r = await $fetch('https://openrouter.ai/api/v1/chat/completions',{
        method:'POST',
        headers:{'Authorization':'Bearer '+cfg.or_key,'Content-Type':'application/json','HTTP-Referer':'https://evezos.app.n8n.cloud'},
        body:JSON.stringify({model:'meta-llama/llama-3.3-70b-instruct:free',max_tokens:max,
          messages:[{role:'system',content:sys},{role:'user',content:usr}]})
      });
      const t=r.choices[0].message.content;
      try{return{out:JSON.parse(t.replace(/```json|```/g,'').trim()),via:'openrouter'};}
      catch{return{out:{raw:t.slice(0,800)},via:'openrouter'};}
    }catch(e){}
  }
  return {out:{error:'Paste your GROQ key into the Config node. Free at console.groq.com'},via:'none'};
}

