const cfg   = $('Config').first().json;
const forge = $('Forge').first().json;

const res={posted:false,tweet_id:null,tweet_text:forge.tweet,status:'',ts:new Date().toISOString()};

const hasCreds=!!(cfg.tw_ak&&cfg.tw_as&&cfg.tw_at&&cfg.tw_ats);
const autoPost=(cfg.auto_post==='true');

if(!hasCreds){
  res.status='PREVIEW — add Twitter keys to Config node to go live';
  res.preview=forge.tweet;
  return [{json:res}];
}
if(!autoPost){
  res.status='PREVIEW — set auto_post to true in Config node';
  res.preview=forge.tweet;
  return [{json:res}];
}

// Note: Twitter v2 write requires OAuth 1.0a user-context signing.
// Bearer token is read-only. To post: in n8n UI add a Twitter OAuth credential,
// then swap this code node for a built-in Twitter node using that credential.
try{
  const r=await $fetch('https://api.twitter.com/2/tweets',{
    method:'POST',
    headers:{'Content-Type':'application/json','Authorization':'Bearer '+cfg.tw_bearer},
    body:JSON.stringify({text:forge.tweet.slice(0,280)})
  });
  if(r.data&&r.data.id){
    res.posted=true; res.tweet_id=r.data.id;
    res.tweet_url='https://x.com/evez666/status/'+r.data.id;
    res.status='POSTED ✅';
  }else{
    res.status='OAuth1.0a needed for write — see Config node comment';
  }
}catch(e){
  res.status='Error: '+e.message;
}
return [{json:res}];

const cfg   = $('Config').first().json;
const forge = $('Forge').first().json;

const trigger = forge.spawn_agent;
const mon     = forge.monetization;

if(!trigger&&!mon) return [{json:{spawned:false,reason:'No spawn signal this cycle'}}];
if(!cfg.n8n_key)   return [{json:{spawned:false,reason:'Add n8n_key to Config node (n8n Settings → API)'}}];

const name    = (trigger&&trigger.name)||('SPAWN:auto:'+(mon&&mon.type||'monitor'));
const purpose = (trigger&&trigger.purpose)||(mon&&mon.detail||'monitor opportunity');
const schedH  = (trigger&&trigger.schedule==='daily')?24:12;

const subWF={
  name,
  nodes:[
    {id:'s1',name:'Trigger',type:'n8n-nodes-base.scheduleTrigger',typeVersion:1.3,position:[0,0],
     parameters:{rule:{interval:[{field:'hours',hoursInterval:schedH}]}}},
    {id:'s2',name:'Task',type:'n8n-nodes-base.code',typeVersion:2,position:[280,0],
     parameters:{jsCode:'// Agent: '+purpose+'\nreturn [{json:{agent:"'+name+'",status:"monitoring",ts:new Date().toISOString()}}];'}}
  ],
  connections:{Trigger:{main:[[{node:'Task',type:'main',index:0}]]}},
  settings:{executionOrder:'v1',availableInMCP:true}
};

try{
  const created=await $fetch(cfg.n8n_url+'/api/v1/workflows',{
    method:'POST',
    headers:{'X-N8N-API-KEY':cfg.n8n_key,'Content-Type':'application/json'},
    body:JSON.stringify(subWF)
  });
  return [{json:{spawned:true,id:created.id,name,purpose,ts:new Date().toISOString()}}];
}catch(e){
  return [{json:{spawned:false,error:e.message}}];
}

const s     = $('OmniScout').first().json;
const brain = $('Brain').first().json;
const forge = $('Forge').first().json;
const tw    = $('Twitter').first().json;
const spawn = $('Spawn').first().json;

function H(d){let h=5381,str=typeof d==='string'?d:JSON.stringify(d);for(let i=0;i<str.length;i++){h=((h<<5)+h)+str.charCodeAt(i);h|=0;}return 'sha_'+Math.abs(h).toString(16).padStart(16,'0');}

const session={
  slot:s.slot, mode:brain._mode, ai:brain._via,
  tweet:tw.tweet_text, posted:tw.posted,
  image:forge.img_ok, spawned:spawn.spawned,
  fear_greed:s.fear_greed&&s.fear_greed[0]?s.fear_greed[0].val+' '+s.fear_greed[0].label:'?',
  trending:(s.trending||[]).slice(0,2).map(c=>c.sym).join('+'),
  confidence:forge.confidence,
  entry_hash:H(s.slot+'|'+(tw.tweet_text||'')),
  ts:new Date().toISOString(), pid:335
};

$fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger',
  {method:'POST',body:{event_type:'NEST_SESSION',payload:session}}).catch(()=>{});

const fg=s.fear_greed&&s.fear_greed[0]?s.fear_greed[0].val+' '+s.fear_greed[0].label:'?';
const trend=(s.trending||[]).slice(0,3).map(c=>c.sym+(c.chg>=0?'+':'')+c.chg+'%').join(' ');

return [{json:{
